"""Tests for agentpulse.tray.app (non-blocking helpers)."""

from pathlib import Path

import pytest


def test_build_menu_contains_required_items() -> None:
    pytest.importorskip("pystray")

    from agentpulse.tray import app
    from agentpulse.tray.state import TrayState

    state = TrayState()
    menu = app._build_menu(
        state=state,
        config_path=Path("/tmp/c.json"),
        log_path=Path("/tmp/log"),
    )
    # pystray.Menu is iterable over MenuItem objects.
    texts = []
    for item in menu:
        text_attr = getattr(item, "text", None)
        if callable(text_attr):
            continue
        texts.append(str(text_attr))
    joined = "|".join(texts)
    assert "Open logs" in joined
    assert "Open config" in joined
    assert "Stop service" in joined
    assert "Restart service" in joined
    assert "Quit" in joined


def test_load_icon_image_returns_image() -> None:
    pytest.importorskip("PIL")

    from agentpulse.tray import app

    img = app._load_icon_image(connected=True)
    assert img.size == (64, 64)
